import{_ as e,C as p,o as l,c as i,ag as s,E as t}from"./chunks/framework.CAXxHpAX.js";const g=JSON.parse('{"title":"6. ETL / ELT：数据如何进入大数据系统","description":"说明 PostgreSQL 数据如何通过批量同步、CDC、转换和调度进入数据平台。","frontmatter":{"title":"6. ETL / ELT：数据如何进入大数据系统","description":"说明 PostgreSQL 数据如何通过批量同步、CDC、转换和调度进入数据平台。","prev":{"text":"5. 数据仓库建模：从表设计到分析建模","link":"/chapters/05-data-warehouse-modeling"},"next":{"text":"7. 批处理系统：Hive / Spark / Trino","link":"/chapters/07-batch-processing"}},"headers":[],"relativePath":"chapters/06-etl-elt.md","filePath":"chapters/06-etl-elt.md"}'),r={name:"chapters/06-etl-elt.md"};function c(o,a,d,b,u,h){const n=p("Mermaid");return l(),i("div",null,[a[0]||(a[0]=s('<h1 id="_6-etl-elt-数据如何进入大数据系统" tabindex="-1">6. ETL / ELT：数据如何进入大数据系统 <a class="header-anchor" href="#_6-etl-elt-数据如何进入大数据系统" aria-label="Permalink to &quot;6. ETL / ELT：数据如何进入大数据系统&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>说明 PostgreSQL 数据如何通过批量同步、CDC、转换和调度进入数据平台。</p></div><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',4)),t(n,{code:"flowchart%20LR%0A%20%20P%5B%22PostgreSQL%22%5D%20--%3E%20B%5B%22Batch%20Extract%22%5D%0A%20%20P%20--%3E%20C%5B%22CDC%20%2F%20WAL%22%5D%0A%20%20B%20--%3E%20W%5B%22Data%20Warehouse%22%5D%0A%20%20C%20--%3E%20K%5B%22Kafka%22%5D%0A%20%20K%20--%3E%20F%5B%22Flink%22%5D%0A%20%20F%20--%3E%20O%5B%22OLAP%20%2F%20Lakehouse%22%5D%0A%20%20W%20--%3E%20BI%5B%22BI%20%2F%20%E6%8C%87%E6%A0%87%22%5D%0A"}),a[1]||(a[1]=s(`<p>数据不是天然在数仓里。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>业务数据最初通常在 PostgreSQL、MySQL、业务日志、第三方系统或外部文件中。要让这些数据进入分析平台，必须经过抽取、同步、清洗、转换、装载和调度。</p><p>第 5 章已经设计了数仓模型：ODS、DWD、DWS、ADS，事实表、维度表和指标口径都已经明确。但模型只是目标形态，真实系统还要回答更工程化的问题：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL 里的订单数据什么时候进入 ODS？</span></span>
<span class="line"><span>全量同步和增量同步如何切换？</span></span>
<span class="line"><span>源表新增字段后，下游任务会不会失败？</span></span>
<span class="line"><span>同步任务失败一天后，如何补回缺失数据？</span></span>
<span class="line"><span>CDC 消费变慢时，WAL 会不会堆积？</span></span>
<span class="line"><span>同一条订单变更被消费两次，指标会不会重复？</span></span>
<span class="line"><span>数据到达以后，怎样证明它完整、准确、及时？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>如果这些问题没有设计清楚，数仓模型再漂亮也无法稳定运行。数据链路一旦不可信，下游报表、特征、RAG 知识库和治理系统都会失去基础。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>大数据平台的核心不是某一个计算引擎，而是持续、可信、可追踪的数据链路。</p></blockquote><p>本章要建立的判断是：ETL / ELT 解决的不是“把数据搬走”，而是让源系统数据以可恢复、可验证、可追踪的方式进入分析系统。</p><p>它的边界也要明确。ETL / ELT 不能替代数仓建模，不能自动统一指标口径，不能让错误源数据变正确，也不能单独保证端到端 Exactly Once。它提供的是数据进入平台的工程链路，后续仍需要建模、质量、血缘、权限和调度治理。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_6-1-etl、elt-与数据链路" tabindex="-1">6.1 ETL、ELT 与数据链路 <a class="header-anchor" href="#_6-1-etl、elt-与数据链路" aria-label="Permalink to &quot;6.1 ETL、ELT 与数据链路&quot;">​</a></h3><p>ETL 是 Extract、Transform、Load。</p><p>先抽取数据，再转换数据，最后加载到目标系统。</p><p>ELT 是 Extract、Load、Transform。</p><p>先抽取并加载到目标存储，再在目标系统中转换。</p><p>两者不是谁更高级，而是系统条件不同。</p><p>如果目标数仓计算能力强，ELT 更常见。例如先把 PostgreSQL 数据同步到 Snowflake、BigQuery、ClickHouse、Hive 或 Iceberg，再用 SQL / dbt / Spark 做转换。</p><p>如果源端或中间层需要提前清洗，ETL 更合适。例如对敏感字段脱敏、对文件格式做标准化、对异常数据提前过滤。</p><p>数据链路至少要回答：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据从哪里来？</span></span>
<span class="line"><span>什么时候同步？</span></span>
<span class="line"><span>全量还是增量？</span></span>
<span class="line"><span>如何处理 schema 变化？</span></span>
<span class="line"><span>失败后如何重跑？</span></span>
<span class="line"><span>如何保证不重复、不丢失？</span></span>
<span class="line"><span>如何验证质量？</span></span>
<span class="line"><span>谁负责这条链路？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="_6-2-postgresql-数据抽取方式" tabindex="-1">6.2 PostgreSQL 数据抽取方式 <a class="header-anchor" href="#_6-2-postgresql-数据抽取方式" aria-label="Permalink to &quot;6.2 PostgreSQL 数据抽取方式&quot;">​</a></h3><p>PostgreSQL 常见抽取方式包括：</p><ul><li>JDBC 抽取。</li><li><code>pg_dump</code>。</li><li><code>COPY</code>。</li><li>Logical Replication。</li><li>WAL。</li><li>CDC。</li><li>Foreign Data Wrapper。</li></ul><p>JDBC 抽取适合通用批量读取，但要注意分页、快照一致性、主键范围和源库压力。</p><p><code>pg_dump</code> 适合备份、迁移和全量导出，不适合高频分析同步。</p><p><code>COPY</code> 适合高效导入导出表数据。</p><p>Logical Replication 和 WAL 是增量同步、CDC 和实时链路的重要基础。更准确地说，WAL 先服务数据库可靠性和崩溃恢复：数据页变更必须先写入日志，数据库才能在故障后通过日志重放恢复一致状态。Logical Decoding 则把 WAL 中偏底层的变更记录解码成外部系统能消费的逻辑变更流；Logical Replication 在这个基础上通过发布、订阅、walsender、apply worker 和输出插件把变更复制到订阅端。</p><p>Foreign Data Wrapper 可以让 PostgreSQL 访问外部数据源，但它不是通用数据平台的替代品。</p><p>抽取方式的核心判断是：</p><blockquote><p>数据抽取不是把数据拿出来这么简单，而是在源库压力、同步延迟、一致性、成本和可恢复性之间做取舍。</p></blockquote><h3 id="_6-3-cdc-从定时同步到变更流" tabindex="-1">6.3 CDC：从定时同步到变更流 <a class="header-anchor" href="#_6-3-cdc-从定时同步到变更流" aria-label="Permalink to &quot;6.3 CDC：从定时同步到变更流&quot;">​</a></h3><p>CDC 是 Change Data Capture，变更数据捕获。</p><p>批量同步通常按时间或主键周期性拉取数据。CDC 则关注数据库中发生的每一次插入、更新和删除。</p><p>PostgreSQL 的 CDC 通常基于 WAL 和 Logical Decoding：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL WAL</span></span>
<span class="line"><span>  -&gt; Logical Decoding</span></span>
<span class="line"><span>  -&gt; Replication Slot</span></span>
<span class="line"><span>  -&gt; Debezium</span></span>
<span class="line"><span>  -&gt; Kafka Connect</span></span>
<span class="line"><span>  -&gt; Kafka Topic</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个链路里，Replication Slot 不是“消息队列”，而是 PostgreSQL 用来记录变更消费位置的机制。slot 会让消费者能从上次位置继续读取变更；但如果消费者长期停止或落后，数据库需要保留它还没有消费的 WAL 和相关资源，这就是 CDC 链路可能导致源库存储压力的根源。</p><p>Logical Decoding 也不等于所有 CDC 产品本身。它提供把 PostgreSQL 变更解码出来的数据库能力；Debezium、Kafka Connect、Flink CDC 或自研程序再把这些变更转成下游事件、处理 schema 变化、维护偏移量、做重试和写入目标系统。</p><p>CDC 的价值在于：</p><ul><li>低延迟获取变更。</li><li>减少全表扫描。</li><li>支持实时数仓。</li><li>支持缓存更新。</li><li>支持事件驱动架构。</li></ul><p>但 CDC 也有成本：</p><ul><li>需要管理 replication slot。</li><li>下游消费慢可能导致 WAL 堆积。</li><li>schema 变更需要兼容处理。</li><li>删除和更新语义要明确。</li><li>Exactly Once 需要端到端设计，不是单个组件自动保证。</li></ul><p>CDC 的核心判断是：</p><blockquote><p>CDC 把数据库从静态数据源变成持续产生事件流的源头。</p></blockquote><h3 id="_6-4-批量同步工具" tabindex="-1">6.4 批量同步工具 <a class="header-anchor" href="#_6-4-批量同步工具" aria-label="Permalink to &quot;6.4 批量同步工具&quot;">​</a></h3><p>常见批量同步工具包括：</p><ul><li>Airbyte。</li><li>Fivetran。</li><li>Meltano。</li><li>DataX。</li><li>Sqoop。</li><li>自研同步脚本。</li></ul><p>这些工具解决的是连接器和同步流程标准化问题。</p><p>它们通常负责：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>连接源系统</span></span>
<span class="line"><span>读取数据</span></span>
<span class="line"><span>处理增量字段</span></span>
<span class="line"><span>写入目标系统</span></span>
<span class="line"><span>记录同步状态</span></span>
<span class="line"><span>处理失败重试</span></span>
<span class="line"><span>管理 schema</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>工具选型不要只看支持多少连接器，还要看：</p><ul><li>是否支持目标系统。</li><li>增量同步是否可靠。</li><li>schema 演化是否可控。</li><li>失败恢复是否清晰。</li><li>运行日志是否可观察。</li><li>是否适合团队运维能力。</li></ul><h3 id="_6-5-转换工具" tabindex="-1">6.5 转换工具 <a class="header-anchor" href="#_6-5-转换工具" aria-label="Permalink to &quot;6.5 转换工具&quot;">​</a></h3><p>同步只把数据搬到目标系统，转换才把数据变成可分析结构。</p><p>常见转换工具包括：</p><ul><li>dbt。</li><li>Spark SQL。</li><li>Flink SQL。</li><li>SQLMesh。</li><li>自研 SQL 任务。</li></ul><p>dbt 的核心价值是把 SQL 转换过程工程化：模型依赖、测试、文档、血缘、版本管理和环境管理。</p><p>Spark SQL 适合大规模离线转换。</p><p>Flink SQL 适合流式转换和实时指标。</p><p>SQLMesh 关注 SQL 模型变更、环境和回填管理。</p><p>转换工具的核心判断是：</p><blockquote><p>转换不是写几条 SQL，而是把数据模型、依赖、质量和发布流程工程化。</p></blockquote><h3 id="_6-6-调度工具" tabindex="-1">6.6 调度工具 <a class="header-anchor" href="#_6-6-调度工具" aria-label="Permalink to &quot;6.6 调度工具&quot;">​</a></h3><p>调度工具负责让任务按依赖和时间运行。</p><p>常见工具包括：</p><ul><li>Airflow。</li><li>Dagster。</li><li>DolphinScheduler。</li><li>Azkaban。</li><li>Cron。</li></ul><p>Cron 可以跑简单任务，但复杂数据平台需要表达 DAG 依赖：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>同步订单表</span></span>
<span class="line"><span>  -&gt; 清洗订单明细</span></span>
<span class="line"><span>  -&gt; 生成用户日汇总</span></span>
<span class="line"><span>  -&gt; 刷新经营看板</span></span>
<span class="line"><span>  -&gt; 触发质量检查</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>调度系统不只负责“按时运行”，还要负责失败重试、补数、依赖管理、告警、日志和责任追踪。</p><h3 id="_6-7-典型链路" tabindex="-1">6.7 典型链路 <a class="header-anchor" href="#_6-7-典型链路" aria-label="Permalink to &quot;6.7 典型链路&quot;">​</a></h3><p>批量同步链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; Airbyte / DataX</span></span>
<span class="line"><span>  -&gt; Data Warehouse</span></span>
<span class="line"><span>  -&gt; dbt</span></span>
<span class="line"><span>  -&gt; BI Dashboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>适合 T+1 报表、经营分析和低实时要求指标。</p><p>实时 CDC 链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; Debezium</span></span>
<span class="line"><span>  -&gt; Kafka</span></span>
<span class="line"><span>  -&gt; Flink</span></span>
<span class="line"><span>  -&gt; ClickHouse / Doris / Iceberg</span></span>
<span class="line"><span>  -&gt; 实时看板</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>适合订单监控、实时风控、实时指标和事件驱动系统。</p><p>湖仓链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; Airbyte / CDC</span></span>
<span class="line"><span>  -&gt; Object Storage</span></span>
<span class="line"><span>  -&gt; Parquet</span></span>
<span class="line"><span>  -&gt; Iceberg / Delta / Hudi</span></span>
<span class="line"><span>  -&gt; Trino / Spark</span></span>
<span class="line"><span>  -&gt; BI / AI 应用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>适合开放存储、多引擎分析、长期归档和 AI 数据准备。</p><h3 id="深度展开-etl-elt如何落到真实系统" tabindex="-1">深度展开：ETL / ELT如何落到真实系统 <a class="header-anchor" href="#深度展开-etl-elt如何落到真实系统" aria-label="Permalink to &quot;深度展开：ETL / ELT如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>分析系统不能凭空得到数据。数据必须从业务系统被抽取、同步、转换、校验和装载。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入包括全量表、增量时间戳、数据库日志、文件、消息流、接口数据和调度上下文。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是先决定全量还是增量，再决定批量抽取还是 CDC，接着处理 schema 变化、幂等写入、失败重跑、质量校验和血缘记录。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>真实平台会使用 Airflow、Dagster、Flink CDC、Debezium、Kafka Connect、Spark、dbt 或自研任务，把 PostgreSQL 数据稳定送入数仓、OLAP 或湖仓。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>ETL / ELT 解决数据流转，不自动解决业务语义。同步成功不代表指标正确；链路实时不代表结果可信；CDC 捕获变更也不代表消费端一定幂等。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>源表字段变化导致下游任务失败</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>重跑后数据重复</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>增量条件漏数</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>源系统和数仓对账不一致</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>为订单表设计全量初始化、每日增量、CDC 同步、失败重跑和对账 SQL，明确每一步的输入、输出和校验指标。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>ETL / ELT 位于业务系统和分析系统之间，是数据平台的入口层。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL / MySQL / Logs / Files</span></span>
<span class="line"><span>  -&gt; Extract / CDC</span></span>
<span class="line"><span>  -&gt; Load</span></span>
<span class="line"><span>  -&gt; Transform</span></span>
<span class="line"><span>  -&gt; Data Warehouse / OLAP / Lakehouse</span></span>
<span class="line"><span>  -&gt; BI / Feature / RAG / Governance</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>它承接第 5 章的模型设计：ODS 要接收源表，DWD 要依赖清洗和标准化，DWS 要依赖稳定明细，ADS 要依赖汇总结果。它也引出第 7 章的批处理系统：当转换数据量继续变大，单机 SQL 和简单调度就不够，需要 Hive、Spark、Trino 等分布式分析体系。</p><p>从 AI 数据系统角度看，ETL / ELT 也不是传统数仓专属能力。文档进入 RAG 知识库、日志进入评测集、用户行为进入特征平台、图谱边关系进入 GraphRAG，都需要类似的数据链路：抽取、清洗、转换、装载、质量检查和血缘记录。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>一个电商团队通常会同时存在两条链路。</p><p>第一条是 T+1 经营分析链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL orders / users / products / payments</span></span>
<span class="line"><span>  -&gt; 每日凌晨批量抽取</span></span>
<span class="line"><span>  -&gt; ODS 原始表</span></span>
<span class="line"><span>  -&gt; dbt / Spark SQL 清洗成 DWD 明细</span></span>
<span class="line"><span>  -&gt; DWS 日汇总</span></span>
<span class="line"><span>  -&gt; ADS 经营看板</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这条链路更关注完整性、可补数和口径稳定。它允许小时级或天级延迟，但不能丢数据，也不能让昨天的 GMV 因为任务失败悄悄少算。</p><p>第二条是实时订单状态链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL WAL</span></span>
<span class="line"><span>  -&gt; Logical Decoding / Replication Slot</span></span>
<span class="line"><span>  -&gt; Debezium</span></span>
<span class="line"><span>  -&gt; Kafka</span></span>
<span class="line"><span>  -&gt; Flink</span></span>
<span class="line"><span>  -&gt; ClickHouse / Doris</span></span>
<span class="line"><span>  -&gt; 实时订单监控</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这条链路更关注低延迟、变更顺序和消费恢复。它可以服务实时风控、异常支付监控、实时大盘和订单状态提醒。</p><p>两条链路不互相替代。批量链路适合稳定对账和历史回算，实时链路适合低延迟监控和事件驱动。成熟平台通常同时保留两者，并通过质量校验和对账任务确认它们在关键指标上保持一致。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：ETL 就是搬数据。</strong></p><p>搬运只是表层动作。真正重要的是数据一致性、质量、恢复、依赖、监控和责任边界。</p><p><strong>误区二：CDC 一定比批处理好。</strong></p><p>CDC 适合低延迟变更同步，但复杂度更高。低频报表和历史归档未必需要 CDC。</p><p><strong>误区三：有调度就有数据平台。</strong></p><p>调度只是运行任务。数据平台还需要建模、质量、血缘、权限、指标和可观测性。</p><p><strong>误区四：同步成功就代表数据可信。</strong></p><p>任务状态成功只说明程序跑完了，不代表数据量正确、主键没有重复、字段没有异常、指标没有波动。数据链路必须配套质量检查和对账。</p><p><strong>误区五：Exactly Once 是单个组件开关。</strong></p><p>端到端一致性涉及源端变更捕获、消息队列、计算引擎、目标写入、幂等设计和故障恢复。单个组件宣称支持某种语义，不等于整条链路天然不重不丢。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>设计 PostgreSQL 到数仓的两条链路：</p><ol><li>批量同步链路：订单、用户、商品每日同步到数仓。</li><li>实时 CDC 链路：订单状态变化实时进入 Kafka 和 Flink。</li></ol><p>每条链路写清：</p><ul><li>源表。</li><li>同步方式。</li><li>目标系统。</li><li>延迟要求。</li><li>失败重试策略。</li><li>质量检查。</li><li>下游应用。</li></ul><p>补充要求：</p><ul><li>为批量链路设计一次失败补数流程。</li><li>为 CDC 链路设计一次 schema 变更处理流程。</li><li>为两条链路各写 3 条质量检查规则。</li><li>说明哪些指标需要批量链路作为最终对账口径，哪些指标可以使用实时链路作为近实时观察口径。</li></ul><p>示例质量规则：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders 当日同步行数不应低于过去 7 日均值的 70%</span></span>
<span class="line"><span>orders.order_id 在 DWD 明细表中必须唯一</span></span>
<span class="line"><span>payments 成功支付金额与订单支付金额差异必须在可解释范围内</span></span>
<span class="line"><span>CDC topic 消费延迟超过 10 分钟必须告警</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>ETL / ELT 把 PostgreSQL 从业务数据库连接到数据平台。</p><p>CDC 进一步把数据库变更变成事件流。</p><p>下一章进入批处理系统。</p><p>因为当历史数据越来越多，转换和计算就不能只依赖单机数据库，而需要 Hive、Spark、Trino 这类分布式分析体系。</p>`,142))])}const C=e(r,[["render",c]]);export{g as __pageData,C as default};
